<!DOCTYPE html>\n<html lang="en">\n<head>\n    <meta charset="UTF-8">\n    <meta name="viewport" content="width=device-width, initial-scale=1.0">\n    <title>Painel Empresário</title>\n    <style>\n        table { width: 100%; border-collapse: collapse; }\n        th, td { border: 1px solid #dddddd; text-align: left; padding: 8px; }\n        th { background-color: #f2f2f2; }\n    </style>\n</head>\n<body>\n    <h1>Painel Empresário</h1>\n    <table>\n        <tr>\n            <th>Product</th>\n            <th>Cost</th>\n            <th>Price</th>\n            <th>Margin</th>\n            <th>MOD</th>\n            <th>CIF</th>\n            <th>ICMS</th>\n            <th>Margin Percentage</th>\n            <th>Commission Percentage</th>\n        </tr>\n        <tr>\n            <td><input type="text" name="product[]"></td>\n            <td><input type="number" name="cost[]" step="0.01"></td>\n            <td><input type="number" name="price[]" step="0.01"></td>\n            <td><input type="number" name="margin[]" step="0.01"></td>\n            <td><input type="number" name="mod[]" step="0.01"></td>\n            <td><input type="number" name="cif[]" step="0.01"></td>\n            <td><input type="number" name="icms[]" step="0.01"></td>\n            <td><input type="number" name="margin_percentage[]" step="0.01" placeholder="%"></td>\n            <td><input type="number" name="commission_percentage[]" step="0.01" placeholder="%"></td>\n        </tr>\n        <!-- Repeat the above <tr> for more products as necessary -->\n    </table>\n</body>\n</html>\n